import React, { useState, useEffect, useRef } from 'react';
import { 
  User, 
  Crown,
  Cpu,
  Component,
  Palette,
  Database,
  LineChart,
  Mail,
  Linkedin,
  ChevronRight,
  TrendingUp,
  Menu,
  X
} from 'lucide-react';

// Estilos de fuentes
const fontStyles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400&family=Montserrat:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;1,100;1,200;1,300;1,400&family=Inter:wght@100;200;300;400;500;600;700&display=swap');
  
  .font-playfair {
    font-family: 'Playfair Display', serif;
  }
  
  .font-montserrat {
    font-family: 'Montserrat', sans-serif;
  }
  
  .font-inter {
    font-family: 'Inter', sans-serif;
  }

  .header-icon-button {
    all: unset;
    box-sizing: border-box;
    margin: 0;
    padding: 0;
    border: none;
    background: none;
    font: inherit;
    color: inherit;
    cursor: pointer;
    outline: none;
  }

  .header-icon-button:focus {
    outline: none;
    ring: none;
  }

  .header-icon-button:hover {
    background: none !important;
    border: none !important;
  }
`;

// Componente Reveal
const Reveal = ({ children, delay = 0 }) => {
  const [isVisible, setIsVisible] = useState(false);
  
  useEffect(() => {
    const timer = setTimeout(() => {
      setIsVisible(true);
    }, delay);
    
    return () => clearTimeout(timer);
  }, [delay]);
  
  return (
    <div className={`transition-all duration-700 ease-out ${
      isVisible 
        ? 'opacity-100 translate-y-0' 
        : 'opacity-0 translate-y-8'
    }`}>
      {children}
    </div>
  );
};

const EquipoPage = () => {
  const [activeSection, setActiveSection] = useState('delegacion');
  const [isHeaderShrunk, setIsHeaderShrunk] = useState(false);
  const [asideBottom, setAsideBottom] = useState('auto');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const sectionRefs = useRef({});
  const asideRef = useRef(null);
  const uneteRef = useRef(null);
  const [scrollY, setScrollY] = useState(0);
  const tickingRef = useRef(false);

  // Insertar estilos en el head del documento
  useEffect(() => {
    const styleElement = document.createElement('style');
    styleElement.textContent = fontStyles;
    document.head.appendChild(styleElement);
    
    return () => {
      document.head.removeChild(styleElement);
    };
  }, []);

  // Scroll handler para parallax, sticky navigation y cálculo del aside
  useEffect(() => {
    const calculateAsideBottom = () => {
      const aside = asideRef.current;
      const uneteSection = uneteRef.current;
      
      if (!aside || !uneteSection) return;
      
      const asideRect = aside.getBoundingClientRect();
      const uneteRect = uneteSection.getBoundingClientRect();
      const viewportHeight = window.innerHeight;
      
      if (uneteRect.top < viewportHeight - 2 * 16) {
        const distanceFromBottom = viewportHeight - uneteRect.top + 2 * 16;
        setAsideBottom(`${distanceFromBottom / 16}rem`);
      } else {
        setAsideBottom('2rem');
      }
    };

    const handleScroll = () => {
      setIsHeaderShrunk(window.scrollY > 100);
      
      if (!tickingRef.current) {
        requestAnimationFrame(() => {
          setScrollY(window.scrollY);
          calculateAsideBottom();
          tickingRef.current = false;
        });
        tickingRef.current = true;
      }

      const sections = ['delegacion', 'backend', 'frontend', 'diseno', 'basedatos', 'dashboard', 'unete'];
      const scrollPosition = window.scrollY + 12.5 * 16;

      for (const sectionId of sections) {
        const element = sectionRefs.current[sectionId];
        if (element) {
          const { offsetTop, offsetHeight } = element;
          if (scrollPosition >= offsetTop && scrollPosition < offsetTop + offsetHeight) {
            setActiveSection(sectionId);
            break;
          }
        }
      }
    };
    
    window.addEventListener('scroll', handleScroll, { passive: true });
    window.addEventListener('resize', calculateAsideBottom);
    
    calculateAsideBottom();
    
    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('resize', calculateAsideBottom);
    };
  }, []);

  const scrollTo = (e, id) => {
    e.preventDefault();
    const el = sectionRefs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.scrollY;
    const offsetPosition = elementPosition - 6.25 * 16;
    
    window.scrollTo({ top: offsetPosition, behavior: "smooth" });
    setActiveSection(id);
    setMobileMenuOpen(false);
  };

  const parallaxStyle = {
    transform: `translate3d(0, ${scrollY * 0.4}px, 0)`
  };

  // Secciones con iconos
  const sections = [
    { 
      id: 'delegacion', 
      label: 'LIDERAZGO', 
      icon: Crown,
      bgColor: 'bg-white'
    },
    { 
      id: 'backend', 
      label: 'BACKEND', 
      icon: Cpu,
      bgColor: 'bg-gray-50'
    },
    { 
      id: 'frontend', 
      label: 'FRONTEND', 
      icon: Component,
      bgColor: 'bg-white'
    },
    { 
      id: 'diseno', 
      label: 'DISEÑO', 
      icon: Palette,
      bgColor: 'bg-gray-50'
    },
    { 
      id: 'basedatos', 
      label: 'BASE DE DATOS', 
      icon: Database,
      bgColor: 'bg-white'
    },
    { 
      id: 'dashboard', 
      label: 'ANALITYCS', 
      icon: LineChart,
      bgColor: 'bg-gray-50'
    }
  ];

  // Logos de los cuerpos
  const bodyLogos = [
    { id: 'delegacion', name: 'Liderazgo', icon: Crown, section: 'delegacion' },
    { id: 'backend', name: 'Backend', icon: Cpu, section: 'backend' },
    { id: 'frontend', name: 'Frontend', icon: Component, section: 'frontend' },
    { id: 'diseno', name: 'Diseño', icon: Palette, section: 'diseno' },
    { id: 'basedatos', name: 'Base de Datos', icon: Database, section: 'basedatos' },
    { id: 'dashboard', name: 'Analytics', icon: LineChart, section: 'dashboard' }
  ];

  // Datos de ejemplo del equipo
  const teamMembers = {
    delegacion: [
      { 
        id: 1, 
        name: 'Ana Rodríguez', 
        position: 'Project Manager', 
        skills: ['Liderazgo', 'Estrategia', 'Gestión'],
        email: 'ana.rodriguez@orbis.com',
        linkedin: 'https://linkedin.com/in/ana-rodriguez'
      },
      { 
        id: 2, 
        name: 'Carlos Méndez', 
        position: 'Líder de Equipo', 
        skills: ['Coordinación', 'Planificación', 'Mentoría'],
        email: 'carlos.mendez@orbis.com',
        linkedin: 'https://linkedin.com/in/carlos-mendez'
      }
    ],
    backend: [
      { 
        id: 1, 
        name: 'Javier López', 
        position: 'Senior Backend Dev', 
        skills: ['Node.js', 'Python', 'APIs'],
        email: 'javier.lopez@orbis.com',
        linkedin: 'https://linkedin.com/in/javier-lopez'
      }
    ],
    frontend: [
      { 
        id: 1, 
        name: 'Sofía García', 
        position: 'Frontend Lead', 
        skills: ['React', 'TypeScript', 'UX'],
        email: 'sofia.garcia@orbis.com',
        linkedin: 'https://linkedin.com/in/sofia-garcia'
      }
    ],
    diseno: [
      { 
        id: 1, 
        name: 'Claudia Rojas', 
        position: 'Diseñadora Gráfica', 
        skills: ['Illustrator', 'Branding', 'Tipografía'],
        email: 'claudia.rojas@orbis.com',
        linkedin: 'https://linkedin.com/in/claudia-rojas'
      }
    ],
    basedatos: [
      { 
        id: 1, 
        name: 'Roberto Silva', 
        position: 'Database Architect', 
        skills: ['SQL', 'MongoDB', 'Optimización'],
        email: 'roberto.silva@orbis.com',
        linkedin: 'https://linkedin.com/in/roberto-silva'
      }
    ],
    dashboard: [
      { 
        id: 1, 
        name: 'Patricia Navarro', 
        position: 'Dashboard Designer', 
        skills: ['DataViz', 'Tableau', 'Storytelling'],
        email: 'patricia.navarro@orbis.com',
        linkedin: 'https://linkedin.com/in/patricia-navarro'
      }
    ]
  };

  return (
    <div className="min-h-screen bg-beige font-inter">
      
      {/* HEADER RESPONSIVE */}
      <div className="h-[60vh] sm:h-[70vh] md:h-[80vh] min-h-[20rem] sm:min-h-[25rem] max-h-[40rem] sm:max-h-[50rem] mb-6 sm:mb-9 overflow-hidden relative">
        <header className="relative h-full">
          <div className="absolute inset-0 w-full h-full overflow-hidden" style={parallaxStyle}>
            <img 
              src="/media/historiapage/futbol.jpg"
              alt="Nuestro Equipo - Orbis Empresarial"
              className="w-full h-full object-cover object-top"
            />
            <div className="absolute inset-0 bg-black/70"></div>
          </div>
          
          <div className="relative z-30 p-4 sm:p-6 md:p-8 lg:p-12 xl:p-20 text-white h-full flex flex-col justify-center items-center text-center">
            <div className="relative z-10 w-full max-w-6xl px-2">
              {/* TÍTULO RESPONSIVE */}
              <div className="mb-4 sm:mb-6 md:mb-8">
                <h1 className="font-playfair text-3xl sm:text-4xl md:text-5xl lg:text-6xl xl:text-8xl font-normal leading-[0.9] tracking-tight mb-2 sm:mb-4 text-white">
                  Nuestro Equipo
                </h1>
              </div>
              
              {/* SUBTÍTULO RESPONSIVE */}
              <div className="mb-4 sm:mb-6 md:mb-8">
                <h2 className="font-montserrat text-base sm:text-lg md:text-xl lg:text-2xl xl:text-3xl font-light tracking-[0.1em] sm:tracking-[0.2em] uppercase text-white/95 mb-2 sm:mb-3">
                  Talento y Excelencia
                </h2>
                <div className="h-px w-16 sm:w-20 md:w-24 lg:w-32 bg-white/80 mb-2 sm:mb-4 mx-auto"></div>
              </div>
              
              {/* DESCRIPCIÓN RESPONSIVE */}
              <div className="mb-6 sm:mb-8 md:mb-10 lg:mb-12">
                <p className="font-inter text-sm sm:text-base md:text-lg lg:text-xl xl:text-2xl font-extralight tracking-wide max-w-2xl mx-auto text-white/95 leading-relaxed px-2">
                  Conoce al equipo profesional detrás de Orbis Empresarial. 
                  Expertos comprometidos con la excelencia y la innovación.
                </p>
              </div>

              {/* LOGOS EN CAJITA RESPONSIVE */}
              <div className="relative z-10 mt-4 sm:mt-6 md:mt-8 px-2">
                <div className="max-w-4xl mx-auto">
                  <div className="bg-white/10 backdrop-blur-sm rounded-xl sm:rounded-2xl shadow-lg border border-white/20 p-3 sm:p-4 md:p-5 lg:p-6">
                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-6 gap-3 sm:gap-4 md:gap-5 lg:gap-6">
                      {bodyLogos.map((body) => {
                        const IconComponent = body.icon;
                        return (
                          <div key={body.id} className="text-center group">
                            <button
                              onClick={(e) => scrollTo(e, body.section)}
                              className="header-icon-button w-full"
                            >
                              <div className="bg-white/10 rounded-lg sm:rounded-xl p-2 sm:p-3 mb-2 sm:mb-3 mx-auto w-8 h-8 sm:w-10 sm:h-10 md:w-12 md:h-12 flex items-center justify-center group-hover:bg-white/20 transition-colors duration-300">
                                <IconComponent className="w-4 h-4 sm:w-5 sm:h-5 md:w-6 md:h-6 text-white" />
                              </div>
                              <div className="text-xs sm:text-sm font-light text-white/90 font-montserrat tracking-wide">
                                {body.name}
                              </div>
                            </button>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </header>
      </div>

      <main className="py-0">
        {/* NAVEGACIÓN MÓVIL MEJORADA */}
        <div className="block lg:hidden mb-4 sm:mb-6 px-2 sm:px-4">
          <div className="flex justify-between items-center mb-2">
            <h3 className="font-montserrat text-sm text-[#072D42] font-medium">
              Navegar secciones:
            </h3>
            <button
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
              className="p-2 rounded-lg border border-[#072D42]/20 bg-white/50"
            >
              {mobileMenuOpen ? <X className="w-4 h-4" /> : <Menu className="w-4 h-4" />}
            </button>
          </div>
          
          <nav className={`flex flex-col gap-1 transition-all duration-300 ${
            mobileMenuOpen ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0 overflow-hidden'
          }`}>
            {sections.map((s) => (
              <button
                key={s.id}
                onClick={(e) => scrollTo(e, s.id)}
                className={`
                  relative text-left py-2 px-3 transition-all duration-200
                  rounded-lg border border-[#9298A6]/30 bg-white/80
                  hover:bg-[#9298A6]/10 text-left w-full
                  ${
                    activeSection === s.id 
                      ? 'bg-[#9298A6]/20 font-medium'
                      : 'font-light opacity-80 hover:opacity-100'
                  }
                `}
              >
                <div className="flex items-center gap-2">
                  <s.icon className="w-4 h-4 text-[#072D42]" />
                  <span className="tracking-widest text-xs text-[#072D42] font-montserrat">
                    {s.label}
                  </span>
                </div>
              </button>
            ))}
          </nav>
        </div>

        <div className="flex flex-col lg:flex-row gap-4 sm:gap-6 lg:gap-8 lg:items-start px-2 sm:px-4 md:px-6 lg:px-8">
          {/* ASIDE STICKY - SOLO DESKTOP */}
          <aside 
            ref={asideRef}
            className="hidden lg:block lg:w-2/6 sticky"
            style={{ 
              top: '10rem',
              bottom: asideBottom 
            }}
          >
            <nav className="flex lg:flex-col gap-0 rounded-lg overflow-hidden border border-[#9298A6]/30 bg-white/10">
              {sections.map((s) => (
                <button
                  key={s.id}
                  onClick={(e) => scrollTo(e, s.id)}
                  className={`
                    relative group flex items-center justify-between py-3 px-4 transition-all duration-300
                    after:content-[''] after:absolute after:left-0 after:bottom-0
                    after:w-full after:h-px after:bg-[#9298A6]
                    after:origin-center after:transition-transform after:duration-300 after:ease-out
                    border-b border-[#9298A6]/20 last:border-b-0
                    hover:bg-[#9298A6]/10 w-full text-left
                    ${
                      activeSection === s.id 
                        ? 'font-medium opacity-100 after:scale-x-100 bg-[#9298A6]/20'
                        : 'font-extralight opacity-70 hover:opacity-100 after:scale-x-0 hover:after:scale-x-100'
                    }
                  `}
                >
                  <div className="flex items-center gap-3">
                    <s.icon className="w-4 h-4 text-[#072D42] opacity-70 group-hover:opacity-100 transition-opacity duration-300" />
                    <span className={`
                      tracking-widest text-sm text-[#072D42] font-montserrat
                      ${activeSection === s.id ? 'font-semibold' : 'font-extralight'}
                    `}>
                      {s.label}
                    </span>
                  </div>
                  <div className="opacity-0 group-hover:opacity-100 transition-all duration-300 transform translate-x-2 group-hover:translate-x-0">
                    <ChevronRight className="w-3 h-3 text-[#072D42]" />
                  </div>
                </button>
              ))}
            </nav>
          </aside>

          {/* CONTENIDO PRINCIPAL RESPONSIVE */}
          <section className="w-full lg:w-5/6 flex flex-col px-0">
            {sections.map((section, index) => (
              <div key={section.id} className={section.bgColor}>
                {/* SEPARADORES RESPONSIVE */}
                {index > 0 && sections[index - 1].bgColor === section.bgColor && (
                  <div className="h-px w-full bg-gradient-to-r from-transparent via-[#072D42]/10 to-transparent"></div>
                )}

                {index > 0 && sections[index - 1].bgColor !== section.bgColor && (
                  <div className="h-2 sm:h-4 w-full bg-gradient-to-b from-gray-50 to-white"></div>
                )}

                <div
                  id={section.id}
                  ref={(el) => (sectionRefs.current[section.id] = el)}
                  className="scroll-mt-16 sm:scroll-mt-20 md:scroll-mt-24"
                >
                  <div className="py-6 sm:py-8 md:py-10 lg:py-12 xl:py-16 px-2 sm:px-4 md:px-6 lg:px-8">
                    <Reveal delay={index * 100}>
                      <div className="mb-6 sm:mb-8 md:mb-10 lg:mb-12 xl:mb-16 text-center">
                        <div className="flex items-center justify-center gap-2 sm:gap-3 mb-3 sm:mb-4">
                          <section.icon className="w-6 h-6 sm:w-7 sm:h-7 md:w-8 md:h-8 text-[#072D42]" />
                          <h2 className="font-playfair text-xl sm:text-2xl md:text-3xl lg:text-4xl xl:text-5xl text-[#072D42] font-normal">
                            {section.label}
                          </h2>
                        </div>
                        <div className="h-px w-12 sm:w-16 md:w-20 bg-[#072D42]/60 mx-auto"></div>
                      </div>
                    </Reveal>

                    {/* TARJETAS RESPONSIVE */}
                    <div className="flex justify-center">
                      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-3 sm:gap-4 md:gap-5 lg:gap-6 w-full max-w-7xl">
                        {teamMembers[section.id].map((member, memberIndex) => (
                          <Reveal key={member.id} delay={(index * 100) + (memberIndex * 100)}>
                            <div className="relative bg-white rounded-lg sm:rounded-xl md:rounded-2xl shadow-lg border border-[#072D42]/10 hover:shadow-xl hover:border-[#072D42]/20 transition-all duration-500 ease-out group overflow-hidden">
                              
                              <div className="absolute inset-0 bg-gradient-to-br from-[#072D42] to-[#0A3A5A] opacity-0 group-hover:opacity-100 transition-all duration-500 ease-out rounded-lg sm:rounded-xl md:rounded-2xl" />
                              
                              <div className="absolute right-0 top-1/2 transform -translate-y-1/2 flex items-center justify-center opacity-[0.03] group-hover:opacity-[0.15] transition-all duration-700 ease-out z-10">
                                <section.icon className="w-24 h-24 sm:w-32 sm:h-32 md:w-48 md:h-48 text-[#072D42] group-hover:text-white transition-colors duration-500 group-hover:scale-105" />
                              </div>
                              
                              <div className="relative z-20 p-3 sm:p-4 md:p-5">
                                <div className="flex items-start gap-2 sm:gap-3 md:gap-4 mb-2 sm:mb-3 md:mb-4">
                                  <div className="flex-shrink-0">
                                    <div className="w-10 h-10 sm:w-12 sm:h-12 md:w-14 md:h-14 rounded-full bg-gradient-to-br from-[#072D42] to-[#0A3A5A] group-hover:from-white group-hover:to-gray-100 flex items-center justify-center group-hover:scale-110 transition-all duration-500 border-2 border-white group-hover:border-[#072D42] shadow-md">
                                      <User className="w-4 h-4 sm:w-5 sm:h-5 md:w-6 md:h-6 text-white group-hover:text-[#072D42] transition-colors duration-500" />
                                    </div>
                                  </div>
                                  
                                  <div className="flex-1 min-w-0">
                                    <h3 className="font-playfair text-sm sm:text-base md:text-lg text-[#072D42] group-hover:text-white font-normal mb-1 transition-colors duration-300 truncate">
                                      {member.name}
                                    </h3>
                                    <p className="font-inter text-[#072D42]/80 group-hover:text-white/90 text-xs sm:text-sm font-medium truncate transition-colors duration-300">
                                      {member.position}
                                    </p>
                                  </div>
                                </div>
                                
                                <div className="space-y-2 sm:space-y-3">
                                  <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-2 sm:gap-3">
                                      <a 
                                        href={`mailto:${member.email}`}
                                        className="text-[#072D42]/70 group-hover:text-white/80 hover:text-[#072D42] group-hover:hover:text-white transition-colors duration-300 flex items-center gap-1"
                                        title="Enviar email"
                                      >
                                        <Mail className="w-3 h-3 flex-shrink-0" />
                                        <span className="text-xs font-inter truncate max-w-[80px] sm:max-w-[100px] md:max-w-[120px]">
                                          {member.email.split('@')[0]}
                                        </span>
                                      </a>
                                      
                                      <a 
                                        href={member.linkedin}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="text-[#072D42]/70 group-hover:text-white/80 hover:text-[#0077B5] group-hover:hover:text-white transition-colors duration-300 flex-shrink-0"
                                        title="LinkedIn"
                                      >
                                        <Linkedin className="w-3 h-3 sm:w-4 sm:h-4" />
                                      </a>
                                    </div>
                                  </div>
                                  
                                  <div className="flex flex-wrap gap-1">
                                    {member.skills.map((skill, skillIndex) => (
                                      <span 
                                        key={skillIndex}
                                        className="inline-flex items-center px-1.5 sm:px-2 py-0.5 sm:py-1 bg-[#F8F5F0] group-hover:bg-white/20 text-[#072D42] group-hover:text-white text-xs rounded-md font-inter transition-all duration-300 hover:bg-[#F4E9D7] group-hover:hover:bg-white/30"
                                      >
                                        {skill}
                                      </span>
                                    ))}
                                  </div>
                                </div>
                              </div>
                            </div>
                          </Reveal>
                        ))}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}

            {/* SEPARADOR ELEGANTE RESPONSIVE */}
            <div className="flex items-center justify-center my-8 sm:my-12 md:my-16 bg-white py-4 sm:py-6 md:py-8">
              <div className="h-px w-16 sm:w-24 md:w-32 bg-[#072D42]/20"></div>
              <div className="mx-2 sm:mx-3 md:mx-4">
                <TrendingUp className="w-4 h-4 sm:w-5 sm:h-5 md:w-6 md:h-6 text-[#072D42]/40" />
              </div>
              <div className="h-px w-16 sm:w-24 md:w-32 bg-[#072D42]/20"></div>
            </div>
          </section>
        </div>

        {/* SECCIÓN "ÚNETE" RESPONSIVE */}
        <div 
          id="unete"
          ref={(el) => {
            sectionRefs.current.unete = el;
            uneteRef.current = el;
          }}
          className="scroll-mt-16 sm:scroll-mt-20 md:scroll-mt-24 relative min-h-[20rem] sm:min-h-[25rem] md:min-h-[31.25rem] w-screen -ml-[calc(50vw-50%)] -mr-[calc(50vw-50%)] mt-8 sm:mt-12 md:mt-16"
        >
          <div className="absolute inset-0 w-full h-full">
            <img 
              src="/media/historiapage/TEAMB.jpg"
              alt="Únete a nuestro equipo"
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-br from-[#072D42]/90 to-[#0A3A5A]/90"></div>
          </div>
          
          <div className="relative z-10 py-12 sm:py-16 md:py-20 lg:py-24">
            <Reveal>
              <div className="text-center max-w-3xl mx-auto text-white px-4 sm:px-6">
                <h2 className="font-playfair text-2xl sm:text-3xl md:text-4xl lg:text-5xl text-white mb-4 sm:mb-5 md:mb-6 font-normal">
                  Únete a Nuestro Equipo
                </h2>
                <div className="h-px w-16 sm:w-20 bg-white/70 mx-auto mb-4 sm:mb-6 md:mb-8"></div>
                <p className="font-inter text-white/90 mb-6 sm:mb-8 md:mb-10 text-sm sm:text-base md:text-lg leading-relaxed max-w-2xl mx-auto px-2">
                  Buscamos talento apasionado por la innovación 
                  y la preservación de la memoria empresarial.
                </p>
                <button className="bg-white/20 hover:bg-white/30 text-white px-6 py-3 sm:px-8 sm:py-4 rounded-lg font-montserrat font-medium tracking-wide transition-all duration-300 transform hover:scale-105 hover:shadow-xl text-sm sm:text-base md:text-lg border border-white/30 hover:border-white/50">
                  Ver Oportunidades
                </button>
              </div>
            </Reveal>
          </div>
        </div>
      </main>
    </div>
  );
};

export default EquipoPage;
